class Solution:
    def myAtoi(self, s: str) -> int:
        MAX_INT, MIN_INT = 2**31 - 1, -2**31
        sign = 1
        num = 0
        start = False

        for c in s:
            if not start and c == ' ':
                continue
            elif not start and (c == '-' or c == '+'):
                sign = -1 if c == '-' else 1
                start = True
            elif c.isdigit():
                start = True
                num = num * 10 + int(c)
            else:
                break

        num *= sign
        if num > MAX_INT:
            return MAX_INT
        elif num < MIN_INT:
            return MIN_INT
        else:
            return num

