class Solution:
    def generateParenthesis(self, n):
        def backtrack(open_p, close_p, path):
            if len(path) == 2 * n:
                result.append(''.join(path))
                return
            if open_p < n:
                path.append('(')
                backtrack(open_p + 1, close_p, path)
                path.pop()
            if close_p < open_p:
                path.append(')')
                backtrack(open_p, close_p + 1, path)
                path.pop()

        result = []
        backtrack(0, 0, [])
        return result

