        if len(nums) <= 1:
            return 0
        max_reach = nums[0]
        step = nums[0]
        jumps = 1
        for i in range(1, len(nums)):
            if i == len(nums) - 1:
                return jumps
            max_reach = max(max_reach, i + nums[i])
            step -= 1
            if step == 0:
